-- PostgreSQL seed for Cruises database

CREATE TABLE IF NOT EXISTS cruise_lines (
  id VARCHAR(255) PRIMARY KEY,
  name VARCHAR(255) NOT NULL,
  slug VARCHAR(255) UNIQUE NOT NULL,
  river_cruise BOOLEAN,
  expedition_cruise BOOLEAN,
  adults_only BOOLEAN,
  luxury_level VARCHAR(50),
  commission_rate NUMERIC,
  hq_country VARCHAR(100),
  description TEXT
);


CREATE TABLE IF NOT EXISTS ships (
  id VARCHAR(255) PRIMARY KEY,
  cruise_line_id VARCHAR(255),
  name VARCHAR(255),
  tonnage INT,
  passenger_capacity INT,
  crew_size INT,
  launch_year INT
);

